:root {
  --bg: #0b0f1a;
  --bg-elev: #131a2c;
  --bg-card: rgba(22, 30, 50, 0.72);
  --border: rgba(120, 150, 220, 0.18);
  --text: #e6ecff;
  --muted: #8a95b8;
  --accent: #7c5cff;
  --accent-2: #36d6ff;
  --success: #4ade80;
  --warn: #fbbf24;
  --danger: #f87171;
  --code-bg: rgba(8, 12, 24, 0.85);
  --shadow: 0 30px 60px -20px rgba(0, 0, 0, 0.6);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI',
    Roboto, sans-serif;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  background: var(--bg);
  color: var(--text);
  min-height: 100%;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

body {
  background:
    radial-gradient(1200px 600px at 80% -10%, rgba(124, 92, 255, 0.25), transparent 60%),
    radial-gradient(1000px 500px at -10% 30%, rgba(54, 214, 255, 0.18), transparent 60%),
    var(--bg);
  overflow-x: hidden;
}

#stars {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  opacity: 0.55;
}

#app {
  position: relative;
  z-index: 1;
  max-width: 1080px;
  margin: 0 auto;
  padding: 56px 24px 80px;
}

.hero {
  text-align: center;
  margin-bottom: 56px;
}

.badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 14px;
  border: 1px solid var(--border);
  border-radius: 999px;
  background: rgba(22, 30, 50, 0.6);
  backdrop-filter: blur(8px);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 24px;
}

.badge .dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--success);
  box-shadow: 0 0 12px var(--success);
  animation: pulse 1.6s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 0.6; transform: scale(0.9); }
  50%      { opacity: 1;   transform: scale(1.1); }
}

h1 {
  font-size: clamp(2rem, 5vw, 3.4rem);
  line-height: 1.1;
  font-weight: 800;
  margin: 0 0 18px;
  letter-spacing: -0.02em;
}

.gradient-text {
  background: linear-gradient(120deg, var(--accent) 0%, var(--accent-2) 100%);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  color: transparent;
}

.lede {
  max-width: 640px;
  margin: 0 auto 28px;
  color: var(--muted);
  font-size: 17px;
  line-height: 1.6;
}

.lede code {
  background: var(--code-bg);
  padding: 2px 6px;
  border-radius: 4px;
  color: var(--accent-2);
  font-size: 14px;
}

.hero-actions {
  display: flex;
  gap: 12px;
  justify-content: center;
  flex-wrap: wrap;
}

.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 20px;
  border-radius: 10px;
  border: 1px solid transparent;
  font-family: inherit;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.15s ease, box-shadow 0.15s ease,
    background 0.15s ease;
  text-decoration: none;
  color: var(--text);
  background: rgba(255, 255, 255, 0.05);
  white-space: nowrap;
}

.btn:hover { transform: translateY(-1px); }
.btn:active { transform: translateY(0); }

.btn-primary {
  background: linear-gradient(120deg, var(--accent), var(--accent-2));
  color: #0b0f1a;
  box-shadow: 0 12px 30px -10px rgba(124, 92, 255, 0.6);
}

.btn-primary:hover {
  box-shadow: 0 16px 40px -10px rgba(124, 92, 255, 0.8);
}

.btn-ghost {
  background: transparent;
  border-color: var(--border);
  color: var(--text);
}

.btn-ghost:hover {
  background: rgba(255, 255, 255, 0.04);
}

.btn-small {
  padding: 8px 14px;
  font-size: 13px;
}

.btn .icon {
  font-size: 12px;
}

.grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 20px;
  margin-bottom: 48px;
}

.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 22px;
  backdrop-filter: blur(12px);
  box-shadow: var(--shadow);
  display: flex;
  flex-direction: column;
  gap: 14px;
  transition: transform 0.2s ease, border-color 0.2s ease;
  position: relative;
  overflow: hidden;
}

.card::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg,
    rgba(124, 92, 255, 0.08) 0%,
    transparent 50%);
  pointer-events: none;
  opacity: 0;
  transition: opacity 0.3s ease;
}

.card:hover {
  transform: translateY(-2px);
  border-color: rgba(124, 92, 255, 0.4);
}

.card:hover::before { opacity: 1; }

.card > * { position: relative; z-index: 1; }

.card header {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.tag {
  align-self: flex-start;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  padding: 4px 10px;
  border-radius: 999px;
  background: rgba(124, 92, 255, 0.15);
  color: var(--accent);
}

.card h2 {
  font-size: 17px;
  margin: 0;
  font-weight: 700;
}

.card p {
  margin: 0;
  color: var(--muted);
  font-size: 14px;
  line-height: 1.55;
  flex-grow: 1;
}

.card p code,
.card h2 code {
  background: var(--code-bg);
  padding: 1px 5px;
  border-radius: 3px;
  color: var(--accent-2);
  font-size: 12px;
}

.code {
  margin: 0;
  padding: 14px 16px;
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  font-family: 'JetBrains Mono', 'Fira Code', ui-monospace, monospace;
  font-size: 12.5px;
  line-height: 1.55;
  color: #c5cae9;
  overflow-x: auto;
}

.code code { display: block; white-space: pre; }

.card-action {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
  border-top: 1px dashed var(--border);
  padding-top: 14px;
  margin-top: 4px;
}

output {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12.5px;
  color: var(--muted);
  margin-left: auto;
  padding: 4px 10px;
  border-radius: 6px;
  background: rgba(255, 255, 255, 0.03);
  min-width: 60px;
  text-align: right;
}

output.success { color: var(--success); }
output.error   { color: var(--danger);  }
output.busy    { color: var(--warn);    }

.console {
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 18px 20px;
  box-shadow: var(--shadow);
}

.console header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.console h3 {
  margin: 0;
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--muted);
}

#console-log {
  list-style: none;
  margin: 0;
  padding: 0;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12.5px;
  line-height: 1.6;
  max-height: 220px;
  overflow-y: auto;
}

#console-log li {
  padding: 4px 0;
  border-bottom: 1px solid rgba(120, 150, 220, 0.08);
  display: flex;
  gap: 10px;
}

#console-log li:last-child { border-bottom: none; }

#console-log .ts {
  color: var(--muted);
  flex-shrink: 0;
}

#console-log .msg { color: var(--text); }
#console-log .info  .msg { color: var(--accent-2); }
#console-log .ok    .msg { color: var(--success); }
#console-log .err   .msg { color: var(--danger);  }
#console-log .empty {
  color: var(--muted);
  font-style: italic;
  border: none;
}

.foot {
  text-align: center;
  margin-top: 48px;
  color: var(--muted);
  font-size: 13px;
}

.kbd {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  background: rgba(255, 255, 255, 0.06);
  padding: 2px 6px;
  border-radius: 4px;
  border: 1px solid var(--border);
  font-size: 11.5px;
}

@media (max-width: 640px) {
  #app { padding: 32px 16px 56px; }
  .hero { margin-bottom: 36px; }
  .grid { gap: 14px; }
  .card { padding: 18px; }
}

// Async / await demo: a fake user fetch with a tiny artificial delay.
// Swap fakeFetch for `fetch('/api/...')` to talk to a real endpoint.
const FAKE_USERS = [
  { id: 1, name: 'Ada Lovelace',     email: 'ada@analytical.engine' },
  { id: 2, name: 'Grace Hopper',     email: 'grace@cobol.dev'      },
  { id: 3, name: 'Linus Torvalds',   email: 'linus@kernel.org'     },
  { id: 4, name: 'Margaret Hamilton', email: 'margaret@apollo.nasa' },
];

const fakeFetch = (id) =>
  new Promise((resolve, reject) => {
    setTimeout(() => {
      const user = FAKE_USERS.find((u) => u.id === id);
      user ? resolve(user) : reject(new Error(`No user with id ${id}`));
    }, 350);
  });

export async function runAsyncDemo() {
  const id = 1 + Math.floor(Math.random() * FAKE_USERS.length);
  const start = performance.now();
  const user = await fakeFetch(id);
  const elapsed = Math.round(performance.now() - start);
  return { ...user, elapsed };
}

// Class with a #private field — the value can't be read or mutated
// from outside, only via the public API.
export class Counter {
  #value = 0;

  increment() { this.#value++; }
  decrement() { this.#value--; }
  reset()     { this.#value = 0; }

  get value() { return this.#value; }
}

// Destructuring + defaults + rest collection in a single expression.
export function runDestructureDemo() {
  const user = {
    name: 'Sasha',
    location: 'Berlin',
    languages: ['JS', 'TS', 'Rust'],
    streak: 42,
  };

  const { name, role = 'guest', languages: [primary], ...rest } = user;
  return { name, role, primary, rest };
}

// Generators: build a lazy infinite sequence and pull values out as
// needed. Works with for-of, spread, and Array.from.
export function* fibonacci() {
  let [a, b] = [0, 1];
  while (true) {
    yield a;
    [a, b] = [b, a + b];
  }
}

// Modules: webpack only ships the named exports you actually import,
// so adding utilities to this file costs nothing if they go unused.
import { greet, factorial } from './utils.js';

export function runModulesDemo() {
  const message = greet('Spck');
  const fact = factorial(7);
  return `${message} · 7! = ${fact}`;
}

// Optional chaining (?.) + nullish coalescing (??): defensive reads
// without a wall of `&&` checks.
export function runOptionalDemo() {
  const partial = {
    name: 'Anonymous',
    profile: { score: 0 },
  };

  const city  = partial?.address?.city ?? 'Unknown';
  const score = partial?.profile?.score ?? -1;
  const phone = partial?.contact?.phone ?? 'n/a';

  return { city, score, phone };
}

export const greet = (name) => `Hello, ${name}!`;

export const factorial = (n) =>
  n <= 1 ? 1 : n * factorial(n - 1);

/**
 * ES8 + Webpack Playground
 * ------------------------
 * Each demo below targets one modern JS feature. They share a tiny
 * console widget so you can see results inline. Edit, save, and
 * webpack rebuilds the bundle.
 */
import { runDestructureDemo } from './demos/destructure.js';
import { runAsyncDemo }       from './demos/async.js';
import { runOptionalDemo }    from './demos/optional.js';
import { runModulesDemo }     from './demos/modules.js';
import { fibonacci }          from './demos/iterators.js';
import { Counter }            from './demos/counter.js';

const MAX_LOG_ENTRIES = 50;

const log = createConsole(document.getElementById('console-log'));
const counter = new Counter();
const fib = fibonacci();

const handlers = {
  async: () => withButton('async', async () => {
    const user = await runAsyncDemo();
    log.ok(`Fetched user: ${user.name} (${user.email})`);
    return `${user.name} ✓`;
  }),

  destructure: () => withButton('destructure', async () => {
    const result = runDestructureDemo();
    log.info(`name=${result.name}, role=${result.role}, extras=${JSON.stringify(result.rest)}`);
    return `${result.name} · ${result.role}`;
  }),

  'counter-inc': () => {
    counter.increment();
    setOutput('counter', counter.value);
    log.info(`counter#value → ${counter.value}`);
  },

  'counter-reset': () => {
    counter.reset();
    setOutput('counter', counter.value);
    log.info('counter reset');
  },

  fib: () => {
    const next6 = Array.from({ length: 6 }, () => fib.next().value);
    setOutput('fib', next6.join(', '));
    log.info(`fib → [${next6.join(', ')}]`);
  },

  optional: () => withButton('optional', async () => {
    const result = runOptionalDemo();
    log.info(`city=${result.city}, score=${result.score}`);
    return result.city;
  }),

  modules: () => withButton('modules', async () => {
    const result = runModulesDemo();
    log.info(result);
    return 'imported ✓';
  }),
};

document.addEventListener('click', (event) => {
  const demoBtn = event.target.closest('[data-demo]');
  if (demoBtn) {
    const handler = handlers[demoBtn.dataset.demo];
    if (handler) handler();
    return;
  }

  const actionBtn = event.target.closest('[data-action]');
  if (actionBtn) {
    if (actionBtn.dataset.action === 'run-demo') runEverything();
    if (actionBtn.dataset.action === 'clear-console') log.clear();
  }
});

async function runEverything() {
  log.clear();
  log.info('Running every demo in sequence…');
  for (const key of ['destructure', 'async', 'optional', 'fib', 'counter-inc', 'modules']) {
    await handlers[key]();
    await wait(180);
  }
  log.ok('All demos completed.');
}

function withButton(key, work) {
  setOutput(key, 'working…', 'busy');
  return Promise.resolve()
    .then(work)
    .then((label) => setOutput(key, label, 'success'))
    .catch((err) => {
      log.err(err.message);
      setOutput(key, 'failed', 'error');
    });
}

function setOutput(key, text, state) {
  const el = document.querySelector(`[data-output="${key}"]`);
  if (!el) return;
  el.textContent = text;
  el.className = state || '';
}

function createConsole(root) {
  const emptyState = () => {
    const li = document.createElement('li');
    li.className = 'empty';
    li.textContent = 'No output yet — try a demo above.';
    return li;
  };

  root.appendChild(emptyState());

  function append(kind, msg) {
    if (root.firstElementChild?.classList.contains('empty')) {
      root.innerHTML = '';
    }
    const li = document.createElement('li');
    li.className = kind;
    li.innerHTML = `<span class="ts"></span><span class="msg"></span>`;
    li.querySelector('.ts').textContent = new Date().toLocaleTimeString([], { hour12: false });
    li.querySelector('.msg').textContent = msg;
    root.appendChild(li);
    while (root.children.length > MAX_LOG_ENTRIES) root.removeChild(root.firstElementChild);
    root.scrollTop = root.scrollHeight;
  }

  return {
    info: (m) => append('info', m),
    ok:   (m) => append('ok',   m),
    err:  (m) => append('err',  m),
    clear: () => { root.innerHTML = ''; root.appendChild(emptyState()); },
  };
}

const wait = (ms) => new Promise((r) => setTimeout(r, ms));

initStarfield(document.getElementById('stars'));
log.info('Playground ready. Press “Run all demos” or click a card.');

function initStarfield(canvas) {
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  let stars = [];
  let raf = 0;

  const resize = () => {
    canvas.width  = window.innerWidth;
    canvas.height = window.innerHeight;
    const density = Math.floor((canvas.width * canvas.height) / 9000);
    stars = Array.from({ length: density }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      r: Math.random() * 1.2 + 0.2,
      vx: (Math.random() - 0.5) * 0.06,
      vy: (Math.random() - 0.5) * 0.06,
      a: Math.random() * 0.6 + 0.2,
    }));
  };

  const tick = () => {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    for (const s of stars) {
      s.x = (s.x + s.vx + canvas.width)  % canvas.width;
      s.y = (s.y + s.vy + canvas.height) % canvas.height;
      ctx.beginPath();
      ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(220, 230, 255, ${s.a})`;
      ctx.fill();
    }
    raf = requestAnimationFrame(tick);
  };

  window.addEventListener('resize', resize);
  resize();
  tick();

  window.addEventListener('beforeunload', () => {
    window.removeEventListener('resize', resize);
    cancelAnimationFrame(raf);
  });
}

const webpack = require('webpack');
const path = require('path');

const config = {
  mode: 'development',
  entry: './src/index.js',
  output: {
    path: path.resolve(__dirname, 'dist'),
    filename: 'bundle.js'
  },
  resolve: {
    modules:[
      'node_modules',
      path.join(process.env.NPM_CONFIG_PREFIX || __dirname, 'lib/node_modules')
    ]
  },
  resolveLoader: {
    modules:[
      'node_modules',
      path.join(process.env.NPM_CONFIG_PREFIX || __dirname, 'lib/node_modules')
    ]
  },
  module: {
    rules: [
      {
        test: /\.js$/,
        use: 'babel-loader',
        exclude: /node_modules|cdn_modules/
      }
    ]
  }
};

module.exports = config;
